create table dirkspzm32.pzm_tarifmodelle (
    tarif_name                        varchar2(50 char) not null enable,
    tarif_bemerkung                   varchar2(255 char),
    tarif_ueb_loa                     varchar2(1 char) default 'T' not null enable,
    tarif_ueb_std                     number(*, 2),
    tarif_ueb_basis                   varchar2(10 char) default 'MM' not null enable,
    created_date                      date default sysdate not null enable,
    created_login_id                  number(*, 0) default - 1 not null enable,
    last_change_date                  date,
    last_change_login_id              number(*, 0),
    tarif_fest_std                    varchar2(1 char) default 'F' not null enable,
    tarif_fest_std_je_periode         number(*, 2),
    tarif_fest_std_akz_minus          number(*, 2),
    tarif_13w_schnitt                 varchar2(1 char) default 'T' not null enable,
    tarif_ueb_zeitkonto_p_zk          varchar2(1 char) default null,
    tarif_ueb_zeitkonto_proz          number(*, 2),
    tarif_ueb_basis_ermittlung        varchar2(10 char),
    tarif_ueb_basis_w_tage            number(2, 0),
    tarif_ueb_proz_wie_ueb_auszahlung varchar2(1 char) default 'F' not null enable
);

alter table dirkspzm32.pzm_tarifmodelle
    add constraint pk_pzm_tarifmodelle primary key ( tarif_name )
        using index enable;


